        cat_part = cat_part.replace(' and ', ', ')
        categories = [cat.strip() for cat in cat_part.split(',') if cat.strip()]
    elif 'fields of' in description:
        cat_part = description.split('fields of')[1]
        if '.' in cat_part:
            cat_part = cat_part.split('.')[0]
        cat_part = cat_part.replace(' and ', ', ')
        categories = [cat.strip() for cat in cat_part.split(',') if cat.strip()]

    business_categories[business_ref] = categories

print('__RESULT__:')
print(json.dumps({
    'business_count': len(businesses),
    'sample_categories': list(business_categories.items())[:3]
}))"}

